CREATE TABLE volunteer_profiles (user_id UUID PRIMARY KEY REFERENCES users(id) ON DELETE CASCADE, bio TEXT, skills TEXT[] NOT NULL DEFAULT '{}', city TEXT, state TEXT, availability TEXT[] NOT NULL DEFAULT '{}', remote_ok BOOLEAN NOT NULL DEFAULT false, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE volunteer_opportunities (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), ngo_id UUID NOT NULL REFERENCES ngo_profiles(id), title TEXT NOT NULL, description TEXT NOT NULL, skills TEXT[] NOT NULL DEFAULT '{}', city TEXT, state TEXT, remote BOOLEAN NOT NULL DEFAULT false, availability TEXT[] NOT NULL DEFAULT '{}', capacity INTEGER NOT NULL CHECK(capacity>0), status TEXT NOT NULL DEFAULT 'draft', starts_at TIMESTAMPTZ, ends_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
ALTER TABLE volunteer_applications ADD COLUMN opportunity_id UUID REFERENCES volunteer_opportunities(id);
ALTER TABLE volunteer_applications ADD COLUMN message TEXT;
CREATE UNIQUE INDEX volunteer_application_once ON volunteer_applications(user_id, opportunity_id);
CREATE TABLE volunteer_hours (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), application_id UUID NOT NULL REFERENCES volunteer_applications(id), minutes INTEGER NOT NULL CHECK(minutes>0), service_date DATE NOT NULL, description TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'pending', reviewed_by UUID REFERENCES users(id), reviewed_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE volunteer_certificates (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL REFERENCES users(id), ngo_id UUID NOT NULL REFERENCES ngo_profiles(id), certificate_number TEXT NOT NULL UNIQUE, approved_minutes INTEGER NOT NULL CHECK(approved_minutes>0), issued_at TIMESTAMPTZ NOT NULL DEFAULT now());
ALTER TABLE posts ADD COLUMN title TEXT;
ALTER TABLE posts ADD COLUMN media JSONB NOT NULL DEFAULT '[]';
ALTER TABLE posts ADD COLUMN status TEXT NOT NULL DEFAULT 'published';
ALTER TABLE posts ADD COLUMN featured_at TIMESTAMPTZ;
ALTER TABLE posts ADD COLUMN is_impact_story BOOLEAN NOT NULL DEFAULT false;
CREATE TABLE post_likes (user_id UUID NOT NULL REFERENCES users(id), post_id UUID NOT NULL REFERENCES posts(id) ON DELETE CASCADE, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), PRIMARY KEY(user_id,post_id));
CREATE TABLE post_comments (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL REFERENCES users(id), post_id UUID NOT NULL REFERENCES posts(id) ON DELETE CASCADE, body TEXT NOT NULL, hidden_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), updated_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE post_bookmarks (user_id UUID NOT NULL REFERENCES users(id), post_id UUID NOT NULL REFERENCES posts(id) ON DELETE CASCADE, created_at TIMESTAMPTZ NOT NULL DEFAULT now(), PRIMARY KEY(user_id,post_id));
CREATE TABLE reports (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), reporter_id UUID NOT NULL REFERENCES users(id), entity_type TEXT NOT NULL, entity_id UUID NOT NULL, reason TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'open', reviewed_by UUID REFERENCES users(id), reviewed_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE TABLE notifications (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL REFERENCES users(id) ON DELETE CASCADE, type TEXT NOT NULL, title TEXT NOT NULL, body TEXT NOT NULL, href TEXT, read_at TIMESTAMPTZ, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
CREATE INDEX notifications_user_unread ON notifications(user_id,created_at DESC) WHERE read_at IS NULL;
CREATE TABLE realtime_events (id BIGSERIAL PRIMARY KEY, audience_user_id UUID REFERENCES users(id), topic TEXT NOT NULL, payload JSONB NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT now());
